SCOPE = 'https://purview.azure.net/.default'
tenant_id = os.environ.get('AZURE_TENANT_ID', '').strip()
client_id = os.environ.get('AZURE_CLIENT_ID', '').strip()
client_secret = os.environ.get('AZURE_CLIENT_SECRET', '').strip()
def get_token() -> str:
    cred_chain = ChainedTokenCredential(
        ManagedIdentityCredential(),
        DefaultAzureCredential(exclude_interactive_browser_credential=True, exclude_visual_studio_code_credential=True)
    )
    try:
        return cred_chain.get_token(SCOPE).token
    except Exception:
        if tenant_id and client_id and client_secret:
            import msal
            app = msal.ConfidentialClientApplication(
                client_id, authority=f'https://login.microsoftonline.com/{tenant_id}', client_credential=client_secret
            )
            result = app.acquire_token_for_client(scopes=[SCOPE])
            if 'access_token' in result:
                return result['access_token']
            raise RuntimeError('MSAL service principal auth failed')
        raise

def purview_request(method: str, path: str, *, params: Optional[Dict[str, Any]] = None, json_body: Optional[Dict[str, Any]] = None, retries: int = 3, timeout: int = 60) -> requests.Response:
    url = f'{BASE_URL}{path}'
    last_exc = None
    for attempt in range(retries):
        token = get_token()
        headers = {'Authorization': f'Bearer {token}', 'Content-Type': 'application/json'}
        try:
            resp = requests.request(method, url, headers=headers, params=params, json=json_body, timeout=timeout)
        except Exception as ex:
            last_exc = ex
            time.sleep(min(2 ** attempt, 5))
            continue
        if resp.status_code in (401, 403, 429) and attempt < retries - 1:
            time.sleep(1 + attempt)
            continue
        if resp.status_code >= 500 and attempt < retries - 1:
            time.sleep(1 + attempt)
            continue
        return resp
    if last_exc:
        raise last_exc
    return resp

def search_columns_via_atlas_basic(classifications: List[str], container_filter: str, page_size: int = 100, max_pages: int = 50):
    results = []
    for cls in classifications:
        offset = 0
        for _ in range(max_pages):
            params = {
                'classification': cls,
                'typeName': 'column',
                'query': container_filter,
                'limit': page_size,
                'offset': offset
            }
            resp = purview_request('GET', '/catalog/api/atlas/v2/search/basic', params=params)
            if not resp.ok:
                print(f'Atlas basic search failed for {cls}: {resp.status_code} {resp.text[:200]}')
                break
            data = resp.json()
            items = data.get('entities') or []
            if not items:
                break
            results.extend(items)
            if len(items) < page_size:
                break
            offset += page_size
    return results

def normalize_results(raw_items: list, container_filter: str):
    rows = []
    for it in raw_items:
        guid = it.get('guid') or it.get('id')
        type_name = it.get('typeName')
        attrs = it.get('attributes') or {}
        name = attrs.get('name') or attrs.get('columnName')
        qn = attrs.get('qualifiedName') or it.get('qualifiedName')
        classes = it.get('classifications') or []
        cls_names = []
        for c in classes:
            if isinstance(c, dict):
                n = c.get('typeName') or c.get('name')
                if n: cls_names.append(n)
        parent_qn = qn.split('#', 1)[0] if isinstance(qn, str) else None
        rows.append({
            'guid': guid, 'entityType': type_name, 'column_name': name,
            'qualifiedName': qn, 'parentQualifiedName': parent_qn,
            'classification_names': sorted(set(cls_names))
        })
    import pandas as pd
    df = pd.DataFrame(rows)
    if not df.empty:
        df = df[df['qualifiedName'].astype(str).str.contains(container_filter, case=False, na=False)].copy()
    return df

# Execute search and display results
raw = search_columns_via_atlas_basic(CLASSIFICATION_CANDIDATES, CONTAINER_FILTER)
df = normalize_results(raw, CONTAINER_FILTER)
print(f'Total classified columns found in container {CONTAINER_FILTER}: {len(df)}')
if not df.empty:
    def matched_cls(names):
        for cand in CLASSIFICATION_CANDIDATES:
            for n in names or []:
                if cand.lower() in str(n).lower():
                    return cand
        return None
    df['matched_classification'] = df['classification_names'].apply(matched_cls)
    print('Sample rows:')
    print(df[['column_name','matched_classification','qualifiedName','parentQualifiedName','entityType']].head(50).to_string(index=False))
    try:
        sdf = spark.createDataFrame(df)
        display(sdf)
    except Exception:
        pass
